import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { toast } from 'sonner';
import { User, Mail, Lock, Eye, EyeOff } from 'lucide-react';

const Register = () => {
  const navigate = useNavigate();
  const { register } = useAuth();
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    password: '',
    confirmPassword: '',
  });

  const handleSubmit = (e) => {
    e.preventDefault();

    if (formData.password !== formData.confirmPassword) {
      toast.error('Password dan konfirmasi password tidak cocok');
      return;
    }

    if (formData.password.length < 6) {
      toast.error('Password minimal 6 karakter');
      return;
    }

    const result = register(formData.name, formData.email, formData.password, formData.phone);

    if (result.success) {
      toast.success('Registrasi berhasil! Selamat datang.');
      setTimeout(() => navigate('/'), 1000);
    } else {
      toast.error(result.message);
    }
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  return (
    <div className="min-h-screen flex" data-testid="register-page">
      {/* Left — Hero Image */}
      <div className="hidden lg:block lg:w-3/5 relative">
        <img
          src="/images/truck-hero.jpg"
          alt="Logistics"
          className="absolute inset-0 w-full h-full object-cover"
        />
        {/* Logo overlay */}
        <div className="absolute top-6 left-6 flex items-center gap-3 z-10">
          <img src="/images/logo.png" alt="MPL Logo" className="h-10 w-10 object-contain" />
          <span className="text-white font-bold text-xl tracking-widest uppercase">
            Mandiri Perkasa
          </span>
        </div>
      </div>

      {/* Right — Form Panel */}
      <div className="w-full lg:w-2/5 bg-[#0D0D0D] flex flex-col justify-center px-10 py-12">
        {/* Mobile logo */}
        <div className="flex items-center gap-3 mb-8 lg:hidden">
          <img src="/images/logo.png" alt="MPL Logo" className="h-9 w-9 object-contain" />
          <span className="text-white font-bold text-lg tracking-widest uppercase">
            Mandiri Perkasa
          </span>
        </div>

        <h2
          className="text-4xl font-bold text-[#F5A623] mb-2"
          data-testid="register-title"
        >
          Daftar
        </h2>

        <p className="text-gray-400 text-sm mb-8 leading-relaxed">
          Jika Anda sudah memiliki akun, silakan mendaftar.
          <br />
          kamu dapat{' '}
          <Link
            to="/masuk"
            className="text-[#F5A623] font-semibold hover:underline"
            data-testid="login-link"
          >
            Masuk disini
          </Link>
        </p>

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* Email */}
          <div>
            <label className="block text-sm font-semibold text-white mb-2">Email</label>
            <div className="flex items-center border-b border-gray-600 focus-within:border-[#F5A623] transition-colors">
              <Mail className="h-4 w-4 text-gray-500 mr-3 shrink-0" />
              <input
                name="email"
                type="email"
                required
                value={formData.email}
                onChange={handleChange}
                placeholder="Masukan Email Anda"
                className="w-full bg-transparent py-2 text-white placeholder-gray-500 text-sm focus:outline-none"
                data-testid="register-email"
              />
            </div>
          </div>

          {/* Nama Pengguna */}
          <div>
            <label className="block text-sm font-semibold text-white mb-2">Nama Pengguna</label>
            <div className="flex items-center border-b border-gray-600 focus-within:border-[#F5A623] transition-colors">
              <User className="h-4 w-4 text-gray-500 mr-3 shrink-0" />
              <input
                name="name"
                type="text"
                required
                value={formData.name}
                onChange={handleChange}
                placeholder="Masukan Nama Pengguna"
                className="w-full bg-transparent py-2 text-white placeholder-gray-500 text-sm focus:outline-none"
                data-testid="register-name"
              />
            </div>
          </div>

          {/* Kata Kunci */}
          <div>
            <label className="block text-sm font-semibold text-white mb-2">Kata Kunci</label>
            <div className="flex items-center border-b border-gray-600 focus-within:border-[#F5A623] transition-colors">
              <Lock className="h-4 w-4 text-gray-500 mr-3 shrink-0" />
              <input
                name="password"
                type={showPassword ? 'text' : 'password'}
                required
                value={formData.password}
                onChange={handleChange}
                placeholder="Masukan Kata Sandi Anda"
                className="w-full bg-transparent py-2 text-white placeholder-gray-500 text-sm focus:outline-none"
                data-testid="register-password"
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="ml-2 shrink-0"
                data-testid="toggle-password"
              >
                {showPassword ? (
                  <Eye className="h-4 w-4 text-gray-500" />
                ) : (
                  <EyeOff className="h-4 w-4 text-gray-500" />
                )}
              </button>
            </div>
          </div>

          {/* Konfirmasi Kata Sandi */}
          <div>
            <label className="block text-sm font-semibold text-white mb-2">
              Konfirmasi Kata Sandi
            </label>
            <div className="flex items-center border-b border-gray-600 focus-within:border-[#F5A623] transition-colors">
              <Lock className="h-4 w-4 text-gray-500 mr-3 shrink-0" />
              <input
                name="confirmPassword"
                type={showConfirm ? 'text' : 'password'}
                required
                value={formData.confirmPassword}
                onChange={handleChange}
                placeholder="Konfirmasi Kata Sandi Anda"
                className="w-full bg-transparent py-2 text-white placeholder-gray-500 text-sm focus:outline-none"
                data-testid="register-confirm-password"
              />
              <button
                type="button"
                onClick={() => setShowConfirm(!showConfirm)}
                className="ml-2 shrink-0"
              >
                {showConfirm ? (
                  <Eye className="h-4 w-4 text-gray-500" />
                ) : (
                  <EyeOff className="h-4 w-4 text-gray-500" />
                )}
              </button>
            </div>
          </div>

          {/* Submit */}
          <div className="pt-4">
            <button
              type="submit"
              className="w-full py-3 bg-[#F5A623] text-black font-bold text-base rounded-full hover:bg-[#e09518] transition-colors"
              data-testid="register-submit-button"
            >
              Daftar
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Register;
